import React from "react";
import axios from "axios";
import PostContent from "./PostContent";

const Posts = ({ posts, updatePost, user }) => {
  const deletePost = (id) => {
    axios.delete(`http://localhost:8000/posts/${id}`).then((res) => {
      //console.log(res);
      updatePost(id);
    });
  };
  return (
<div>

{posts.length === 0
    ? "Create a post!"
    : posts.map((post) => {
        return (

              <PostContent
                key={post.id}
                post={post}
                deletePost={deletePost}
                user={user}
              />

        );
      })}
</div>
  )
};
export default Posts;
